package com.panini.back.service; import com.panini.back.entity.*; import com.panini.back.repository.*; import jakarta.annotation.PostConstruct; import org.springframework.stereotype.Service; import java.util.*; @Service public class StickerService { private final StickerRepository stickers; private final CategoryRepository categories; public StickerService(StickerRepository stickers, CategoryRepository categories){ this.stickers=stickers; this.categories=categories; } @PostConstruct public void seed(){ if(stickers.count()>0) return; upsertCategory("FWC","FWC"); upsertCategory("COUNTRY","Pays"); upsertCategory("COCA","Coca-Cola"); seedSticker("FRA1","Team Logo","TEAM","FRA","FWC",1,true); seedSticker("FRA2","Mike Maignan","PLAYER","FRA","COUNTRY",1,false); seedSticker("FRA20","Kylian Mbappe","PLAYER","FRA","COUNTRY",1,false); seedSticker("COCA1","Coca-Cola Promo","SPECIAL","WW","COCA",10,true); } private Category upsertCategory(String code,String label){ return categories.findByCode(code).orElseGet(()->{ Category c=new Category(); c.setCode(code); c.setLabel(label); return categories.save(c); }); } private void seedSticker(String code,String name,String type,String country,String category,Integer page,boolean special){ Sticker s=new Sticker(); s.setCode(code); s.setName(name); s.setType(type); s.setCountryCode(country); s.setCategoryCode(category); s.setPageNumber(page); s.setSpecialSticker(special); stickers.save(s); } public List<Sticker> all(){ return stickers.findAll(); } public List<Sticker> search(String q){ return (q==null||q.isBlank())?stickers.findAll():stickers.findByNameContainingIgnoreCaseOrCodeContainingIgnoreCase(q,q); } public List<Sticker> byCategory(String code){ return stickers.findByCategoryCodeIgnoreCase(code); } public List<Sticker> byCountry(String code){ return stickers.findByCountryCodeIgnoreCase(code); } }
